// [v4.1.5] Lower Third Basic — Frame-Math determinista, DOM cacheado en awake
dvEngine.register({
  awake: (ctx) => {
    ctx.refs.container = ctx.root.getElementById('plugin-container');
    ctx.refs.line      = ctx.root.getElementById('accent-line');
    ctx.refs.title     = ctx.root.getElementById('title-text');
    ctx.refs.subtitle  = ctx.root.getElementById('subtitle-text');
    ctx.refs.glow      = ctx.root.getElementById('glow-bg');
  },

  update: (ctx) => {
    const { frame, refs, props, utils, env, timeline } = ctx;
    const { container, line, title, subtitle, glow } = refs;
    if (!container || !line || !title || !subtitle) return;

    // 1. Datos Reactivos
    title.innerText    = props.title    || 'Ana García';
    subtitle.innerText = props.subtitle || 'Directora de Producto';
    container.style.setProperty('--accent', props.brandPrimaryColor || '#E44C30');

    // 2. Animación de Entrada via introProgress
    const ip = utils.clamp(timeline.introProgress, 0, 1);

    // Línea de acento: escala desde la izquierda
    line.style.transform = `scaleX(${utils.easeOutCubic(ip)})`;

    // Título: desliza desde abajo con retraso leve
    const titleP = utils.clamp((ip - 0.1) / 0.9, 0, 1);
    title.style.opacity   = titleP.toString();
    title.style.transform = `translateY(${utils.lerp(25, 0, utils.easeOutCubic(titleP))}px)`;

    // Subtítulo: aparece después del título
    const subP = utils.clamp((ip - 0.25) / 0.75, 0, 1);
    subtitle.style.opacity   = subP.toString();
    subtitle.style.transform = `translateY(${utils.lerp(20, 0, utils.easeOutCubic(subP))}px)`;

    // 3. Salida via outroProgress
    if (timeline.isOutro) {
      const op = utils.clamp(timeline.outroProgress, 0, 1);
      container.style.opacity   = (1 - utils.easeInOutCubic(op)).toString();
      container.style.transform = `translateX(${utils.lerp(0, -30, utils.easeInOutCubic(op))}px)`;
    } else {
      container.style.opacity = '1';
    }

    // 4. Optimización para exportación
    if (env.isExporting && glow) {
      glow.style.backdropFilter = 'none';
      glow.style.background     = 'rgba(0,0,0,0.75)';
    }
  }
});

// [v4.1.5] News Ticker Pro — Loop determinista basado en frame, DOM cacheado
dvEngine.register({
    awake: (ctx) => {
        ctx.refs.track  = ctx.root.getElementById('ticker-track');
        ctx.refs.text1  = ctx.root.getElementById('ticker-text');
        ctx.refs.text2  = ctx.root.getElementById('ticker-text-copy');
        ctx.refs.label  = ctx.root.getElementById('ticker-label');
        ctx._state      = { x: 0 };
    },

    update: (ctx) => {
        const { frame, props, refs, _state } = ctx;
        const { track, text1, text2, label } = refs;
        if (!track || !text1 || !text2) return;

        // 1. Datos reactivos
        const text = props.tickerText || '— DVGE Engine —';
        if (text1.innerText !== text) {
            text1.innerText = text;
            text2.innerText = text;
        }

        // Color de acento del preset de branding
        const accent = props.brandPrimaryColor || '#E44C30';
        if (label) label.style.background = accent;

        // 2. Desplazamiento determinista por frame (no depende de Date.now)
        const speed    = props.scrollSpeed || 4;
        const textW    = (text1.offsetWidth || 600) + 50;
        _state.x       = -((frame * speed) % textW);

        track.style.transform = `translateX(${_state.x}px)`;
    }
});

// [v4.1.5] Scoreboard Pro — Frame-Math determinista, DOM cacheado en awake
dvEngine.register({
    awake: (ctx) => {
        ctx.refs.board   = ctx.root.getElementById('scoreboard');
        ctx.refs.teamA   = ctx.root.getElementById('team-a-name');
        ctx.refs.scoreA  = ctx.root.getElementById('team-a-score');
        ctx.refs.teamB   = ctx.root.getElementById('team-b-name');
        ctx.refs.scoreB  = ctx.root.getElementById('team-b-score');
        ctx.refs.time    = ctx.root.getElementById('match-time');
        ctx._prevScoreA  = null;
        ctx._prevScoreB  = null;
    },

    update: (ctx) => {
        const { props, refs, timeline, utils } = ctx;
        const { board, teamA, scoreA, teamB, scoreB, time } = refs;
        if (!board || !teamA) return;

        // 1. Datos Reactivos — solo actualizar DOM si cambia el valor
        teamA.innerText  = props.teamA     || 'TEAM A';
        teamB.innerText  = props.teamB     || 'TEAM B';
        time.innerText   = props.matchTime || '1ST HALF';

        // Animación de flash al cambiar puntuación
        const newA = props.scoreA ?? 0;
        const newB = props.scoreB ?? 0;
        if (scoreA.innerText !== String(newA)) {
            scoreA.innerText = newA;
            scoreA.style.transform = 'scale(1.4)';
            setTimeout(() => { if (scoreA) scoreA.style.transform = 'scale(1)'; }, 300);
        }
        if (scoreB.innerText !== String(newB)) {
            scoreB.innerText = newB;
            scoreB.style.transform = 'scale(1.4)';
            setTimeout(() => { if (scoreB) scoreB.style.transform = 'scale(1)'; }, 300);
        }

        // 2. Transición de entrada (desliza desde arriba)
        const ip = utils.clamp(timeline.introProgress, 0, 1);
        const spring = utils.spring(ip, 200, 22);
        board.style.opacity   = ip.toString();
        board.style.transform = `translateY(${utils.lerp(-50, 0, spring)}px)`;

        // 3. Transición de salida (desliza hacia arriba)
        if (timeline.isOutro) {
            const op = utils.clamp(timeline.outroProgress, 0, 1);
            board.style.opacity   = (1 - op).toString();
            board.style.transform = `translateY(${utils.lerp(0, -50, utils.easeInOutCubic(op))}px)`;
        }
    }
});

